def test_open_checking_valid_deposit_mid_range(verified_customer_token, api_client, unique_idempotency_key):
    payload = {
        "initial_deposit": 1000,
        "idempotency_key": unique_idempotency_key
    }
    headers = {
        "Authorization": f"Bearer {verified_customer_token}",
        "Idempotency-Key": unique_idempotency_key
    }
    resp = api_client.post("/accounts/checking", json=payload, headers=headers)
    assert resp.status_code == 201
    body = resp.json()
    assert "account_id" in body
    assert body.get("status") == "active"
    assert body.get("notification_sent") is True

