def test_open_checking_account_state_transitions_to_active(verified_customer_token, api_client, unique_idempotency_key):
    payload = {
        "initial_deposit": 500,
        "idempotency_key": unique_idempotency_key
    }
    headers = {
        "Authorization": f"Bearer {verified_customer_token}",
        "Idempotency-Key": unique_idempotency_key
    }
    create_resp = api_client.post("/accounts/checking", json=payload, headers=headers)
    assert create_resp.status_code == 201
    account_id = create_resp.json().get("account_id")
    assert account_id is not None
    get_resp = api_client.get(f"/accounts/{account_id}", headers=headers)
    assert get_resp.status_code == 200
    assert get_resp.json().get("status") == "active"
